import java.util.PriorityQueue;

public class Solution {
    public static long solve(long[][] grid, long k) {
        int m = grid.length;
        int n = grid[0].length;
        int[][] dirs = {{0, 1}, {1, 0}};
        long[][][] visited = new long[m][n][(int)k + 1];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int l = 0; l <= k; l++) {
                    visited[i][j][l] = Long.MAX_VALUE;
                }
            }
        }
        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[]{0, 0, 0, k});
        visited[0][0][(int)k] = 0;

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long cost = current[0];
            int i = (int)current[1];
            int j = (int)current[2];
            int remainingK = (int)current[3];
            if (i == m - 1 && j == n - 1) {
                return cost;
            }
            if (cost > visited[i][j][remainingK]) {
                continue;
            }
            for (int[] dir : dirs) {
                int ni = i + dir[0];
                int nj = j + dir[1];
                if (ni < 0 || ni >= m || nj < 0 || nj >= n) {
                    continue;
                }
                long newCost = cost + grid[ni][nj];
                if (newCost < visited[ni][nj][remainingK]) {
                    visited[ni][nj][remainingK] = newCost;
                    pq.offer(new long[]{newCost, ni, nj, remainingK});
                }
            }
            if (remainingK > 0) {
                for (int x = 0; x < m; x++) {
                    for (int y = 0; y < n; y++) {
                        if (x == i && y == j) continue;
                        if (grid[x][y] <= grid[i][j]) {
                            if (cost < visited[x][y][remainingK - 1]) {
                                visited[x][y][remainingK - 1] = cost;
                                pq.offer(new long[]{cost, x, y, remainingK - 1});
                            }
                        }
                    }
                }
            }
        }
        return -1;
    }
}
