        pq.offer(new long[]{0, 0, 0, k});
        visited[0][0][(int)k] = 0;

        while (!pq.isEmpty()) {
            long[] curr = pq.poll();
            long cost = curr[0];
            int i = (int)curr[1];
            int j = (int)curr[2];
            int remainingK = (int)curr[3];
            if (i == m - 1 && j == n - 1) {
